import { Loc, Tag, Type } from 'main.core';
import { Dialog, DefaultFooter } from 'ui.entity-selector';

class StorageSelectorFooter extends DefaultFooter
{
	constructor(dialog: Dialog, options: { [option: string]: any })
	{
		super(dialog, options);
	}

	getContent(): HTMLElement | HTMLElement[] | string | null
	{
		return this.cache.remember('write-data-storage-activity', () => {
			return Tag.render`
				<span onclick="${this.#getCreateNewStorageHandler()}" class="ui-selector-footer-link ui-selector-footer-link-add">
					${Loc.getMessage('BIZPROC_WRITE_DATA_ACTIVITY_CREATE_NEW_STORAGE')}
				</span>
			`;
		});
	}

	#getCreateNewStorageHandler(): Promise<(event: MouseEvent) => void>
	{
		const handler = this.getOption('onCreateNewStorageHandler');

		if (Type.isNil(handler) || ! Type.isFunction(handler))
		{
			throw Error('The "onCreateNewStorageHandler" option must be a function.');
		}

		return handler;
	}
}

export default StorageSelectorFooter;